params.content:
{
  "kind": "video-composition-adf",
  "version": "1.0.0",
  "intent": "music-driven video from a governed audio reference",
  "title": "Kyberion Music Video Demo",
  "composition": {
    "duration_sec": 9,
    "fps": 30,
    "width": 1920,
    "height": 1080,
    "background_color": "#07111f"
  },
  "audio": {
    "music_ref": "{{music_path}}"
  },
  "scenes": [
    {
      "scene_id": "hook",
      "role": "hook",
      "start_sec": 0,
      "duration_sec": 3,
      "template_ref": { "template_id": "basic-title-card" },
      "content": {
        "eyebrow": "Kyberion",
        "headline": "Music-driven video, no shell branching",
        "body": "The music track is selected explicitly and carried through the governed render boundary."
      }
    },
    {
      "scene_id": "feature",
      "role": "feature",
      "start_sec": 3,
      "duration_sec": 4,
      "template_ref": { "template_id": "split-highlight" },
      "content": {
        "headline": "Audio stays separate",
        "body": "The music generator and the video renderer keep their own contracts, then mux at the end."
      }
    },
    {
      "scene_id": "outro",
      "role": "outro",
      "start_sec": 7,
      "duration_sec": 2,
      "template_ref": { "template_id": "logo-outro" },
      "content": {
        "headline": "Governed muxing",
        "body": "The final artifact still passes through the same video verification step."
      }
    }
  ],
  "output": {
    "format": "mp4",
    "target_path": "{{video_output_path}}",
    "bundle_dir": "active/shared/exports/music-video-demo-bundle",
    "emit_progress_packets": true,
    "await_completion": true
  }
}
